// Host functions wrappers for float
void rgbToComponents_float(__global float *d_r, __global float *d_g, __global float *d_b, unsigned char * src, int width, int height,
                           cl_command_queue commandQueue, cl_kernel kernel)
{
    int pixels      = width*height;
    int alignedSize =  DIVANDRND(width*height, THREADS) * THREADS * 3; 

    cl_int errNum;
    cl_mem d_src = clCreateBuffer(clGetContext(), CL_MEM_READ_ONLY, alignedSize, NULL, &errNum);
    if (errNum != CL_SUCCESS) { return; }

    // Initialize buffer with zero
    unsigned char zero[alignedSize];
    for(int i=0; i<alignedSize; ++i) zero[i] = 0;
    errNum = clEnqueueWriteBuffer(commandQueue, d_src, CL_TRUE, 0, alignedSize, zero, 0, NULL, NULL);
    if (errNum != CL_SUCCESS) { clReleaseMemObject(d_src); return; }

    errNum = clEnqueueWriteBuffer(commandQueue, d_src, CL_TRUE, 0, pixels*3, src, 0, NULL, NULL);
    if (errNum != CL_SUCCESS) { clReleaseMemObject(d_src); return; }

    size_t globalWorkSize = alignedSize / 3;
    size_t localWorkSize = THREADS;

    errNum  = clSetKernelArg(kernel, 0, sizeof(cl_mem), &d_r);
    errNum |= clSetKernelArg(kernel, 1, sizeof(cl_mem), &d_g);
    errNum |= clSetKernelArg(kernel, 2, sizeof(cl_mem), &d_b);
    errNum |= clSetKernelArg(kernel, 3, sizeof(cl_mem), &d_src);
    errNum |= clSetKernelArg(kernel, 4, sizeof(int), &pixels);
    if (errNum != CL_SUCCESS) { clReleaseMemObject(d_src); return; }

    errNum = clEnqueueNDRangeKernel(commandQueue, kernel, 1, NULL, &globalWorkSize, &localWorkSize, 0, NULL, NULL);
    clFinish(commandQueue);

    clReleaseMemObject(d_src);
}

